window.PREGUNTAS_ADMINISTRATIVO_PI_2022 = [
  { n: 1, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en el artículo 6 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, los registros mercantiles, de la propiedad, y de los protocolos notariales serán interoperables con:", opciones: ["a) Los registros electrónicos singulares y particulares de apoderamientos.","b) Los registros electrónicos singulares de apoderamientos.","c) Los registros electrónicos individuales y generales de apoderamientos.","d) Los registros electrónicos generales y particulares de apoderamientos."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 6.4 Ley 39/2015: interoperables con registros generales y particulares." },
  { n: 2, unidad: "procedimiento-administrativo", pregunta: "En virtud de lo dispuesto en el artículo 6 de la Ley 39/2015 de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, en el Registro Electrónico de Apoderamientos:", opciones: ["a) Cada Administración aprobará los modelos de poderes inscribibles en el registro cuando se circunscriba a actuaciones ante su respectiva Administración.","b) Los poderes inscritos en el registro tendrán una validez determinada máxima de cinco años a contar desde la fecha de inscripción.","c) Los poderes inscritos en el registro tendrán una validez determinada máxima de cinco años a contar desde la fecha de solicitud de inscripción.","d) Las prórrogas otorgadas por el apoderado al registro tendrán una validez determinada máxima de cinco años a contar desde la fecha de inscripción."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 6.5 Ley 39/2015: cada Administración aprueba modelos. Validez es 5 años desde inscripción (no solicitud)." },
  { n: 3, unidad: "organizacion-foral", pregunta: "De conformidad con lo establecido en el artículo 11 de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, las Juntas Generales podrán delegar en la Diputación Foral de Bizkaia:", opciones: ["a) La potestad de dictar disposiciones normativas que afectan al Ordenamiento básico de la Diputación Foral o al Régimen Jurídico de la Administración del Territorio Histórico.","b) La potestad de dictar disposiciones normativas que afectan a la Organización del Territorio Histórico.","c) La potestad de dictar disposiciones normativas sobre el Régimen electoral del Territorio Histórico.","d) Todas aquellas Normas que por su carácter institucional no requieran un procedimiento especial para su aprobación."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 11 NF 3/1987: delegación posible salvo materias institucionales (a, c, d son indelegables)." },
  { n: 4, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en el artículo 21 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, la Administración deberá dictar resolución expresa:", opciones: ["a) Únicamente en los procedimientos iniciados a solicitud del interesado.","b) En los procedimientos iniciados a solicitud del interesado, siempre que una norma de derecho de la unión europea o de derecho internacional aplicable en España no establezcan lo contrario.","c) En todos los procedimientos iniciados a solicitud del interesado, salvo los supuestos de terminación del procedimiento por pacto o convenio, así como los procedimientos relativos al ejercicio de derechos sometidos únicamente al deber de declaración responsable o comunicación a la administración.","d) En todos, cualquiera que sea su forma de finalización."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 21.1 Ley 39/2015: resolución expresa salvo pacto/convenio o declaración responsable/comunicación." },
  { n: 5, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, los plazos expresados en horas se contarán:", opciones: ["a) De hora en hora y no podrá ser superior a cuarenta y ocho horas.","b) En horas y no podrán tener una duración inferior a veinticuatro horas.","c) De hora en hora y de minuto en minuto desde la hora y minuto en que tenga lugar la notificación.","d) En horas y no podrán tener una duración superior a doce horas."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 30.1 Ley 39/2015: de hora en hora y minuto en minuto, no superior a 24h." },
  { n: 6, unidad: "procedimiento-administrativo", pregunta: "Según lo establecido en el artículo 17 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, el archivo de documentos:", opciones: ["a) Las Administraciones deberán mantener archivos electrónicos de los documentos electrónicos que correspondan a procedimientos finalizados, en los términos establecidos en la normativa reguladora aplicable.","b) Los documentos deberán conservarse en un formato que permita garantizar la autenticidad, integridad y conservación del documento, así como su consulta con dependencia del tiempo transcurrido desde su emisión.","c) Se asegurará en todo caso la posibilidad de trasladar los datos a otros formatos y soportes que garanticen el acceso desde diferentes aplicaciones.","d) Los medios o soportes en que se almacenen documentos deberán contar con medidas de seguridad, de acuerdo con lo previsto en el Esquema Nacional de Interoperabilidad, que garanticen la integridad, autenticidad, confidencialidad, calidad, protección y conservación de los documentos almacenados. En particular, asegurarán la identificación de los usuarios y el control de accesos, así como el cumplimiento de las garantías previstas en la legislación de protección de datos."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 17 Ley 39/2015: la c) es literal. La a) dice 'deberán' y b) dice 'dependencia' (debería decir 'independencia'). La d) menciona Esquema Nacional de Interoperabilidad (debería ser Seguridad)." },
  { n: 7, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en el artículo 34 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, en relación con el contenido de los actos administrativos, éste se ajustará:", opciones: ["a) A los fines de aquéllos y servir al interés general.","b) A lo dispuesto por el ordenamiento jurídico y servir equitativamente al interés general.","c) A lo dispuesto por el ordenamiento jurídico y será determinado y adecuado a los fines de aquéllos.","d) A los fines de aquéllos y será determinado y adecuado por el ordenamiento jurídico."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 34.2 Ley 39/2015: ajustado al ordenamiento y adecuado a sus fines." },
  { n: 8, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, la eficacia de los actos:", opciones: ["a) Los actos de las Administraciones Públicas se presumirán válidos y producirán efectos desde la fecha en que se dicten, salvo que en ellos se disponga otra cosa.","b) La eficacia quedará demorada cuando así lo exija el contenido del acto y esté supeditada a su notificación, publicación o aprobación superior.","c) Excepcionalmente, podrá otorgarse eficacia retroactiva a los actos cuando se dicten en sustitución de actos anulados.","d) Los actos de las Administraciones Públicas sujetos al Derecho Administrativo serán ejecutivos con arreglo a lo dispuesto en este Reglamento."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 39.2 Ley 39/2015: la b) es literal. La d) habla de 'Reglamento' cuando es Ley." },
  { n: 9, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, cuando se practica la notificación en papel y el interesado accediera al contenido de la notificación en sede electrónica:", opciones: ["a) El resto de las notificaciones se realizarán a través de medios electrónicos.","b) Se le ofrecerá la posibilidad de que el resto de las notificaciones se puedan realizar a través de medios electrónicos.","c) El resto de las notificaciones se realizarán a través de medios electrónicos excepto la resolución que ponga fin al procedimiento.","d) Ninguna de las respuestas anteriores es correcta."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 42.1 Ley 39/2015: se ofrecerá la posibilidad." },
  { n: 10, unidad: "organizacion-foral", pregunta: "Según lo establecido en el artículo 7 de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, la cesión de competencias a las Instituciones Comunes:", opciones: ["a) Debe ser ratificada por las Juntas Generales.","b) Debe ser aprobada por las Juntas Generales.","c) Debe ser ratificada por la Diputación Foral de Bizkaia.","d) Debe ser aprobada por la Diputada General de Bizkaia."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 7 NF 3/1987: cesión ratificada por Juntas Generales." },
  { n: 11, unidad: "procedimiento-administrativo", pregunta: "Según lo establecido en el artículo 69 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, en relación con la declaración responsable:", opciones: ["a) Las Administraciones podrán requerir en cualquier momento que se aporte la documentación que acredite el cumplimiento de los requisitos de la declaración responsable y el interesado podrá aportarla.","b) La declaración responsable es el documento suscrito por un interesado en el que éste manifiesta, bajo su responsabilidad, que cumple con los requisitos establecidos en la normativa vigente para obtener el reconocimiento de un derecho o facultad o para su ejercicio.","c) La falsedad, esencial o no de cualquier dato o información que se incorpore a una declaración responsable determinará la imposibilidad de continuar con el ejercicio del derecho o actividad afectada desde el momento en que se tenga constancia de tales hechos.","d) La no presentación ante la Administración competente de la declaración responsable, la documentación que sea en su caso requerida para acreditar el cumplimiento de lo declarado, o la comunicación, no determinará la imposibilidad de continuar con el ejercicio del derecho o actividad afectada desde el momento en que se tenga constancia de tales hechos."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 69.1 Ley 39/2015: la b) es la definición literal. La a) dice 'podrá aportarla' (debe). La c) dice 'esencial o no' (sólo esencial). La d) niega la imposibilidad (sí determina)." },
  { n: 12, unidad: "organizacion-foral", pregunta: "Según el artículo 6 de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, de las Juntas Generales de Bizkaia, las Normas Forales de las Juntas Generales serán publicadas en el Boletín Oficial de Bizkaia y entrarán en vigor, salvo disposición en contrario:", opciones: ["a) Al día siguiente de su publicación.","b) A los diez (10) días de su publicación.","c) A los quince (15) días de su publicación.","d) A los veinte (20) días de su publicación."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 6 NF 3/1987: entrada en vigor a los 20 días." },
  { n: 13, unidad: "funcion-publica", pregunta: "Según lo establecido en el artículo 3 de la Ley 11/2022, de 1 de diciembre, de Empleo Público Vasco:", opciones: ["a) Esta ley tendrá carácter supletorio para todo el personal de las administraciones públicas vascas, instituciones públicas u organismos públicos incluidos en su ámbito de aplicación.","b) Cada vez que esta ley haga mención al personal funcionario de carrera no se entenderá comprendido el personal estatutario de Osakidetza-Servicio Vasco de Salud, aplicándose con carácter preferente a dicho personal su normativa específica.","c) A los efectos de esta ley, compone parte del sector público vasco cualquier órgano de naturaleza participativa, consultiva, de asesoramiento o de control dependiente de la Diputación Foral de Bizkaia.","d) Ninguna de las respuestas es correcta."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 3 Ley 11/2022: el personal estatutario de Osakidetza tiene normativa específica preferente." },
  { n: 14, unidad: "procedimiento-administrativo", pregunta: "Según la Ley de Procedimiento Administrativo Común de las Administraciones Públicas, en la ejecución de resoluciones de los actos de las Administraciones Públicas sujetas al Derecho Administrativo, la ejecución forzosa, no se efectuará por el siguiente medio:", opciones: ["a) Ejecución subsidiaria.","b) Acciones posesorias.","c) Multa coercitiva.","d) Compulsión sobre las personas."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 100 Ley 39/2015: medios son apremio, ejecución subsidiaria, multa coercitiva y compulsión. Acciones posesorias NO." },
  { n: 15, unidad: "procedimiento-administrativo", pregunta: "Según la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, ¿qué diferencia existe entre el desistimiento y la renuncia?", opciones: ["a) Podrá renunciar al procedimiento la Administración y podrá desistir del procedimiento el interesado.","b) Al renunciar a un procedimiento administrativo se pierde el derecho a volver a solicitar lo mismo en un momento posterior, mientras que en el desistimiento se desiste de la solicitud, pero se mantiene el derecho.","c) Al desistir de un procedimiento administrativo se pierde el derecho a volver a solicitar lo mismo en un momento posterior, mientras que con la renuncia se desiste de la solicitud, pero se mantiene el derecho.","d) Que la renuncia cabe siempre y el desistimiento no."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Arts. 93-94 Ley 39/2015: renuncia extingue el derecho, desistimiento sólo de la solicitud." },
  { n: 16, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en el artículo 125 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, contra un acto firme en vía administrativa dictado como consecuencia de prevaricación declarada como tal en sentencia judicial firme cabe interponer recurso extraordinario de revisión:", opciones: ["a) Ante el órgano administrativo que lo dictó en el plazo de tres (3) meses desde que la sentencia judicial quedó firme.","b) Ante el superior jerárquico del órgano administrativo que lo dictó en el plazo de un (1) mes desde que la sentencia judicial quedó firme.","c) Ante el órgano administrativo que lo dictó en el plazo de un (1) mes desde que la sentencia judicial quedó firme.","d) Ante el superior jerárquico del órgano administrativo que lo dictó en el plazo de tres (3) meses desde que la sentencia judicial quedó firme."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 125.2 Ley 39/2015: ante el mismo órgano, 3 meses desde firmeza de sentencia (causas b, c, d)." },
  { n: 17, unidad: "procedimiento-administrativo", pregunta: "De conformidad con el artículo 114 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, en el ámbito estatal no ponen fin a la vía administrativa:", opciones: ["a) Los actos administrativos de los miembros y órganos del Gobierno.","b) Los emanados de los Ministros y los Secretarios de Estado en el ejercicio de las competencias que tienen atribuidas los órganos de los que son titulares.","c) Los emanados de los órganos directivos con nivel de Director general o superior, en el ejercicio de las competencias que tienen atribuidas los órganos de los que son titulares.","d) En los Organismos públicos y entidades de derecho público vinculados o dependientes de la Administración General del Estado, los emanados de los máximos órganos de dirección unipersonales o colegiados, de acuerdo con lo que establezcan sus estatutos, salvo que por ley se establezca otra cosa."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 114.2 Ley 39/2015: Director general NO pone fin (a, b, d sí ponen fin)." },
  { n: 18, unidad: "procedimiento-administrativo", pregunta: "De conformidad con el artículo 107 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas (LPACAP), las Administraciones Públicas podrán impugnar:", opciones: ["a) Ante el orden jurisdiccional contencioso-administrativo, los actos desfavorables para los interesados que sean anulables conforme a lo dispuesto en el artículo 48 de la LPACAP, previa su declaración de lesividad para el interés particular.","b) Ante la administración o ante el orden jurisdiccional contencioso-administrativo, los actos favorables para los interesados que sean anulables conforme a lo dispuesto en el artículo 47 de la LPACAP, previa su declaración de lesividad para el interés público.","c) Ante el orden jurisdiccional contencioso-administrativo, los actos favorables para los interesados que sean anulables conforme a lo dispuesto en el artículo 48 de la LPACAP, previa su declaración de lesividad para el interés público.","d) Ninguna es correcta."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 107 Ley 39/2015: declaración de lesividad de actos favorables anulables (art. 48), ante CA." },
  { n: 19, unidad: "funcion-publica", pregunta: "Según lo establecido en el artículo 3 de la Ley 11/2022, de 1 de diciembre, de Empleo Público Vasco, componen el sector público vasco:", opciones: ["a) Las administraciones locales, su respectiva administración institucional y los demás entes instrumentales con personalidad jurídica propia, dependientes o no de cualquiera de las administraciones públicas antes citadas.","b) Las administraciones forales de los territorios históricos, su respectiva administración institucional y los demás entes instrumentales con personalidad jurídica propia, independientes de cualquiera de las administraciones públicas antes citadas.","c) La Administración general de la Comunidad Autónoma de Euskadi.","d) Todas son correctas."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 3 Ley 11/2022: la c) es literal. La a) y b) tienen matices erróneos ('dependientes o no' / 'independientes')." },
  { n: 20, unidad: "procedimiento-administrativo", pregunta: "De conformidad con lo establecido en el artículo 80 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas. La emisión de informes: salvo disposición expresa en contrario, los informes serán:", opciones: ["a) Preceptivos y vinculantes.","b) Facultativos y vinculantes.","c) Preceptivos y no vinculantes.","d) Facultativos y no vinculantes."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 80.1 Ley 39/2015: facultativos y no vinculantes salvo disposición en contrario." },
  { n: 21, unidad: "funcion-publica", pregunta: "En la Ley de Empleo Público Vasco, según el artículo 63, la adquisición de la condición del personal funcionario de carrera y de personal laboral fijo de las administraciones vascas se adquiere por el cumplimiento sucesivo de los siguientes requisitos:", opciones: ["a) Primero: Nombramiento por el órgano o autoridad competente, que será publicado en el «Boletín Oficial del País Vasco» o, en su caso, en el boletín oficial del territorio histórico correspondiente. Segundo: Superación del proceso selectivo, incluidos, en su caso, los correspondientes períodos de prácticas o pruebas. Tercero: Acto en virtud del cual se manifieste que se acata el ordenamiento jurídico. Y cuarto: Toma de posesión dentro del plazo que se establezca o, en su caso, formalización del contrato laboral fijo por el órgano o autoridad competente.","b) Primero: Nombramiento por el órgano o autoridad competente, que será publicado en el «Boletín Oficial del País Vasco» o, en su caso, en el boletín oficial del territorio histórico correspondiente. Segundo: Superación del proceso selectivo, incluidos, en su caso, los correspondientes períodos de prácticas o pruebas. Tercero: Toma de posesión dentro del plazo que se establezca o, en su caso, formalización del contrato laboral fijo por el órgano o autoridad competente. Y cuarto: Acto en virtud del cual se manifieste que se acata el ordenamiento jurídico.","c) Primero: Superación del proceso selectivo, incluidos, en su caso, los correspondientes períodos de prácticas o pruebas. Segundo: Nombramiento por el órgano o autoridad competente, que será publicado en el «Boletín Oficial del País Vasco» o, en su caso, en el boletín oficial del territorio histórico correspondiente. Tercero: Acto en virtud del cual se manifieste que se acata el ordenamiento jurídico. Y cuarto: Toma de posesión dentro del plazo que se establezca o, en su caso, formalización del contrato laboral fijo por el órgano o autoridad competente.","d) Primero: Superación del proceso selectivo, incluidos, en su caso, los correspondientes períodos de prácticas o pruebas. Segundo: Nombramiento por el órgano o autoridad competente, que será publicado en el «Boletín Oficial del País Vasco» o, en su caso, en el boletín oficial del territorio histórico correspondiente. Tercero: Toma de posesión dentro del plazo que se establezca o, en su caso, formalización del contrato laboral fijo por el órgano o autoridad competente. Y cuarto: Acto en virtud del cual se manifieste que se acata el ordenamiento jurídico."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 63 Ley 11/2022: superación, nombramiento, acato y toma de posesión (en ese orden)." },
  { n: 22, unidad: "organizacion-foral", pregunta: "De conformidad con lo establecido en el artículo 27 de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, la Diputada General como Jefa de la Administración Foral, le corresponderá:", opciones: ["a) El ejercicio de las acciones judiciales y extrajudiciales que asistan a la Diputación Foral y los establecimientos que de ella dependan y el personamiento en juicio, en caso de urgencia, dando cuenta a la misma en su primera reunión.","b) Firmar, expedir, publicar los Decretos Forales acordados por la Diputación Foral y por ella misma.","c) Convocar las reuniones de la Diputación Foral, fijar el Orden del Día, presidir sus sesiones, dirigir las deliberaciones, suspender y levantar las sesiones.","d) Prestar a las Juntas Generales la información y ayuda que éstas recaben de la Diputación Foral."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 27 NF 3/1987: como Jefa de Administración Foral, ejerce acciones judiciales (b, c, d corresponden a Presidenta de la DF)." },
  { n: 23, unidad: "funcion-publica", pregunta: "Según lo establecido en el artículo 120 de la Ley 11/2022, de 1 de diciembre, de Empleo Público Vasco se indica que las administraciones públicas vascas retribuirán a su personal funcionario de acuerdo con los conceptos de retribuciones básicas, retribuciones complementarias, pagas extraordinarias y con el siguiente concepto:", opciones: ["a) Trienios.","b) Complemento por productividad.","c) Retribuciones diferidas.","d) Complemento específico."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 120 Ley 11/2022: básicas, complementarias, pagas extraordinarias y retribuciones diferidas." },
  { n: 24, unidad: "funcion-publica", pregunta: "Según lo establecido en la Ley 11/2022, de 1 de diciembre, de Empleo Público Vasco en cuál de los siguientes supuestos no quedará el personal funcionario de carrera en la situación administrativa de servicios especiales:", opciones: ["a) Cuando adquiera la condición de personal funcionario al servicio de organizaciones internacionales.","b) Cuando sea designado personal asesor de los grupos parlamentarios de las Cortes Generales.","c) Cuando mediante el procedimiento de libre designación obtenga un puesto de trabajo en otra administración pública.","d) Cuando sea designado personal asesor de los Grupos Parlamentarios de las Asambleas Legislativas de las Comunidades Autónomas."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Por libre designación en otra AAPP es 'servicio en otras AAPP', no servicios especiales." },
  { n: 25, unidad: "contratos-sector-publico", pregunta: "El artículo 2 de la Ley 9/2017, de 8 de noviembre, de Contratos del Sector Público, por la que se transponen al ordenamiento jurídico español las Directivas del Parlamento Europeo y del Consejo 2014/23/UE y 2014/24/UE, de 26 de febrero de 2014, son contratos onerosos:", opciones: ["a) Aquéllos en los que la contratista obtenga algún tipo de beneficio económico sólo de forma directa.","b) Aquéllos en los que la contratista obtenga algún tipo de prestación o contrapartida por la realización de la prestación.","c) Aquéllos en los que la contratista obtenga algún tipo de beneficio económico, ya sea de forma directa o indirecta.","d) Aquéllos cuyo objeto se considere necesario para la correcta realización de la prestación."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 2.1 LCSP: contratos onerosos son aquellos con beneficio directo o indirecto." },
  { n: 26, unidad: "contratos-sector-publico", pregunta: "Según lo establecido en el artículo 3 de la Ley 9/2017, de 8 de noviembre, de Contratos del Sector Público, a los efectos de esta ley, no se considera que forman parte del sector público las siguientes entidades:", opciones: ["a) Los fondos sin personalidad jurídica.","b) Cualesquiera entidades con personalidad jurídica propia, que hayan sido creadas específicamente para satisfacer necesidades de interés general que no tengan carácter industrial o mercantil, siempre que uno o varios sujetos pertenecientes al sector público financien mayoritariamente su actividad, controlen su gestión, o nombren a menos de la mitad de los miembros de su órgano de administración, dirección o vigilancia.","c) Las Diputaciones Forales.","d) Las Mutuas colaboradoras con la Seguridad Social."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 3 LCSP: en la b) dice 'a menos de la mitad' cuando debería ser 'más de la mitad' para ser sector público; texto mal redactado, no forma parte." },
  { n: 27, unidad: "contratos-sector-publico", pregunta: "De conformidad con lo establecido en la Ley 9/2017, de 8 de noviembre, de Contratos del Sector Público, la incorporación transversal y preceptiva de criterios sociales y medioambientales en la contratación pública:", opciones: ["a) Proporciona mayor calidad-precio en la prestación contractual.","b) Proporciona mayor y mejor eficacia en la utilización de los fondos públicos.","c) Facilita el acceso a la contratación pública de las empresas de economía social.","d) Todas son correctas."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Exposición motivos LCSP: las tres son finalidades de los criterios sociales/ambientales." },
  { n: 28, unidad: "contratos-sector-publico", pregunta: "Según lo dispuesto en el artículo 126 de la Ley 9/2017, de 8 de noviembre, de Contratos del Sector Público, en relación con las prescripciones técnicas:", opciones: ["a) No resulta necesario que definan las calidades, las condiciones sociales y ambientales de conformidad con los requisitos que para cada tipo de contrato establece la Ley de Contratos.","b) Proporcionan a los empresarios acceso en condiciones de igualdad al procedimiento de contratación.","c) Tendrán por efecto la creación de obstáculos injustificados a la apertura de la contratación pública a la competencia.","d) Se redactarán siempre teniendo en cuenta la convención de las Naciones Unidas sobre los derechos de las personas con discapacidad."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 126 LCSP: proporcionan igualdad de acceso. La c) niega obstáculos (no crearán). La d) dice 'siempre' (sólo cuando proceda)." },
  { n: 29, unidad: "contratos-sector-publico", pregunta: "De conformidad con lo establecido en el artículo 130 de la Ley 9/2017, de 8 de noviembre, de Contratos del Sector Público, cuando una Administración Pública decida prestar directamente un servicio que venía siendo prestado por un operador económico, ¿estará obligada a la subrogación del personal que lo prestaba?", opciones: ["a) Sí, en todo caso atendiendo al principio constitucional de seguridad laboral de los trabajadores.","b) Sí, si así lo establece la propia administración en los pliegos de prescripciones técnicas.","c) Sí, salvo que la obligación no se recoja en los pliegos de cláusulas administrativas generales.","d) Sí, si así lo establece una norma legal, un convenio colectivo o un acuerdo de negociación colectiva de eficacia general."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 130 LCSP: subrogación si norma legal, convenio colectivo o acuerdo eficacia general." },
  { n: 30, unidad: "contratos-sector-publico", pregunta: "De conformidad con lo establecido en el artículo 119 de la Ley 9/2017, de 8 de noviembre, de Contratos del Sector Público, los expedientes calificados de urgentes gozarán de preferencia para su despacho por los distintos órganos que intervengan en la tramitación, que dispondrán de un plazo para emitir los respectivos informes o cumplimentar los trámites correspondientes de:", opciones: ["a) Veinte (20) días.","b) Quince (15) días.","c) Diez (10) días.","d) Cinco (5) días."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 119.2.b LCSP: 5 días en tramitación urgente." },
  { n: 31, unidad: "derecho-constitucional", pregunta: "Las normas jurídicas contenidas en los tratados internacionales:", opciones: ["a) En ningún caso puede llegar a tener aplicación directa en España.","b) Aunque no pueden llegar a tener aplicación directa en España, tendrán carácter informador del ordenamiento jurídico interno.","c) Serán de aplicación directa en España desde la firma del tratado internacional correspondiente.","d) Serán de aplicación directa en España cuando hayan pasado a formar parte del ordenamiento interno."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 96.1 CE: aplicación tras publicación oficial en España." },
  { n: 32, unidad: "procedimiento-administrativo", pregunta: "Un reglamento independiente es aquel que:", opciones: ["a) Dicta la Administración para hacer frente a situaciones extraordinarias.","b) De una forma clara y directa desarrolla una norma de rango superior.","c) Regula exclusivamente la organización administrativa.","d) Regula materias no protegidas con reserva de ley."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Reglamento independiente: regula ámbitos no sometidos a reserva de ley." },
  { n: 33, unidad: "procedimiento-administrativo", pregunta: "La potestad discrecional es:", opciones: ["a) Aquella cuyo ejercicio viene totalmente delimitado por una norma sin que quepa la posibilidad de que la Administración realice de forma subjetiva la facultad o poder que se le confiere.","b) La potestad discrecional es la que puede ser ejercida de forma libre \"dicho sea esto con todas las reservas\" por parte de la Administración que la tiene concedida.","c) La que faculta a la Administración para ejercer la tutela o preservación de una relación jurídica.","d) La que faculta para crear, modificar o extinguir las relaciones jurídicas."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "La potestad discrecional permite a la Administración elegir entre alternativas, con reservas (no es arbitrariedad)." },
  { n: 34, unidad: "procedimiento-administrativo", pregunta: "Ley 39/2015 del Procedimiento Administrativo Común de las Administraciones Públicas, en el artículo 129, señala que en el ejercicio de la iniciativa legislativa y la potestad reglamentaria, las Administraciones Públicas actuarán de acuerdo con los principios de:", opciones: ["a) Independencia y proporcionalidad.","b) Necesidad y proporcionalidad.","c) Independencia y seguridad jurídica.","d) Publicidad y transparencia."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 129 Ley 39/2015: necesidad, eficacia, proporcionalidad, seguridad jurídica, transparencia y eficiencia." },
  { n: 35, unidad: "derecho-constitucional", pregunta: "Según lo establecido en los artículos 140 y 141 de la Constitución Española de 1978:", opciones: ["a) Los municipios y las provincias tienen personalidad jurídica plena.","b) Los municipios y las provincias tienen personalidad jurídica propia.","c) Las provincias tienen personalidad jurídica plena.","d) Las provincias tienen personalidad jurídica propia."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Arts. 140 y 141 CE: municipios y provincias tienen personalidad jurídica plena." },
  { n: 36, unidad: "haciendas-locales", pregunta: "En la Ley 7/1985, de 2 de abril, Reguladora de las Bases de Régimen Local, en el artículo 3 se señala que no gozan de la condición de entidades locales:", opciones: ["a) Las Áreas Metropolitanas.","b) Las Mancomunidades de Municipios.","c) Las Comunidades Autónomas.","d) La Isla en el archipiélago canario."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 3 LBRL: las CCAA no son entidades locales." },
  { n: 37, unidad: "proteccion-datos", pregunta: "De conformidad con la Ley 2/2004, de 25 de febrero, de Ficheros de Datos de Carácter Personal de Titularidad Pública y de Creación de la Agencia Vasca de Protección de Datos son funciones de la Agencia Vasca de Protección de Datos:", opciones: ["a) Redactar una memoria anual y remitirla al Parlamento Vasco.","b) Redactar una memoria anual y remitirla al Gobierno Vasco.","c) Redactar una memoria anual y remitirla a la Vicepresidencia del Gobierno Vasco.","d) Redactar una memoria anual y remitirla a la Lehendakaritza del Gobierno Vasco."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 17 Ley 2/2004: memoria anual al Parlamento Vasco." },
  { n: 38, unidad: "proteccion-datos", pregunta: "En el artículo 10 \"Creación y Régimen Jurídico\", de la Ley 2/2004, de 25 de febrero, de Ficheros de Datos de Carácter Personal de Titularidad Pública y de Creación de la Agencia Vasca de Protección de Datos:", opciones: ["a) Se crea la Agencia Vasca de Protección de Datos como ente de derecho público, con personalidad jurídica propia y plena capacidad pública y privada, que actúa con la supervisión del Gobierno Vasco en el ejercicio de sus funciones.","b) Se regirá por lo dispuesto en esta ley y en su estatuto propio, que será aprobado por decreto del Gobierno Vasco a propuesta de la Consejería de Igualdad, justicia y políticas sociales.","c) La representación y defensa en juicio de la Agencia Vasca de Protección de Datos estará a cargo de los servicios jurídicos propios de la Agencia, conforme a lo dispuesto en sus normas reguladoras.","d) La Agencia Vasca de Protección de Datos estará sujeta al derecho público vigente en materia de adquisiciones patrimoniales y contratación. Sus bienes y derechos pertenecerán al patrimonio de la Comunidad Autónoma del País Vasco."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 10 Ley 2/2004: la c) es literal. La a) dice 'con supervisión' (es plena independencia). La b) y d) tienen matices erróneos." },
  { n: 39, unidad: "igualdad", pregunta: "La Norma Foral 4/2018, de 20 de junio, para la igualdad de mujeres y hombres, en su artículo 3.2, principios generales, señala como un principio transversal:", opciones: ["a) La igualdad de trato.","b) La acción positiva.","c) El respeto a la diferencia.","d) La interseccionalidad."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 3.2 NF 4/2018: la interseccionalidad como principio transversal." },
  { n: 40, unidad: "igualdad", pregunta: "Según lo dispuesto en el Título Preliminar del Decreto Legislativo 1/2023, de 16 de marzo, por el que se aprueba el texto refundido de la Ley para la Igualdad de Mujeres y Hombres y Vidas Libres de Violencia Machista contra las Mujeres, el principio de igualdad de trato se aplicará:", opciones: ["a) A las entidades públicas que han suscrito contratos o convenios de colaboración con los poderes públicos vascos.","b) A las entidades privadas que suscriban contratos o convenios de colaboración con los poderes públicos vascos durante el tiempo que dure la relación con el poder público correspondiente.","c) A las entidades públicas que suscriban convenios de colaboración con los poderes públicos vascos durante el tiempo que dure la relación.","d) Todas son incorrectas."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "DL 1/2023: aplica a entidades privadas que suscriban contratos/convenios, durante la relación." },
  { n: 41, unidad: "transparencia", pregunta: "Según el artículo 28 de la Norma Foral 1/2016, de 17 de febrero, de Transparencia de Bizkaia, sobre la composición de la Comisión de Reclamaciones en materia de Transparencia:", opciones: ["a) La Comisión de Reclamaciones en materia de Transparencia se compone de tres (3) miembros titulares y tres (3) suplentes.","b) Deberán pertenecer al funcionariado de carrera de la Diputación Foral, pertenecientes a cuerpos o escalas del Grupo de Clasificación A1 para cuyo ingreso se haya exigido la Licenciatura de Licenciado en Derecho o Grado Universitario del mismo carácter, con un mínimo de tres (3) años de experiencia profesional en tales cuerpos o escalas.","c) El desempeño de las funciones inherentes al cargo de las personas que sean miembros de la Comisión de Reclamaciones en materia de Transparencia conllevará dedicación exclusiva.","d) Las personas que se designen como miembros de la Comisión de Reclamaciones en materia de Transparencia serán nombradas por la Diputada General, y la composición de la misma se publicará en el Portal de Transparencia."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 28 NF 1/2016: nombradas por Diputada General, publicación en Portal de Transparencia." },
  { n: 42, unidad: "derecho-constitucional", pregunta: "De acuerdo con los artículos 10 y 11 de la Ley Orgánica 3/1979, de 18 de diciembre, del Estatuto de Autonomía para el País Vasco, la Comunidad Autónoma del País Vasco no tiene competencia exclusiva en materia de:", opciones: ["a) Ordenación del territorio y litoral, urbanismo y vivienda.","b) Medio ambiente y ecología.","c) Asistencia social.","d) Agricultura y ganadería, de acuerdo con la ordenación general de la economía."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 11 EAPV: medio ambiente es competencia de desarrollo legislativo, no exclusiva (art. 10)." },
  { n: 43, unidad: "derecho-constitucional", pregunta: "A tenor del artículo 11 de la Ley Orgánica 3/1979, de 18 de diciembre, del Estatuto de Autonomía del País Vasco, la competencia de la Comunidad Autónoma del País Vasco en materia de medio ambiente y ecología es:", opciones: ["a) De desarrollo legislativo y ejecución dentro de su territorio de la legislación básica del Estado.","b) Exclusiva.","c) De ejecución de la legislación del Estado.","d) Medio ambiente y ecología no es una competencia contenida en el Estatuto de Autonomía del País Vasco."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 11.1.a EAPV: desarrollo legislativo y ejecución de legislación básica del Estado." },
  { n: 44, unidad: "derecho-constitucional", pregunta: "Según el artículo 28 del Estatuto de Autonomía del País Vasco, Ley Orgánica 3/1979, de 18 de diciembre, solicitar del Gobierno del Estado la adopción de un proyecto de ley corresponde:", opciones: ["a) A la Presidencia o Lehendakaritza del Gobierno Vasco.","b) A la Consejería encargada de la secretaría del Gobierno Vasco.","c) Al Parlamento Vasco.","d) A la Delegación del Gobierno estatal en la Comunidad Autónoma del País Vasco."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 28 EAPV: corresponde al Parlamento Vasco." },
  { n: 45, unidad: "derecho-constitucional", pregunta: "De conformidad con lo establecido en el artículo 45 del Estatuto de Autonomía del País Vasco, Ley Orgánica 3/1979, de 18 de diciembre, la Comunidad Autónoma del País Vasco:", opciones: ["a) Podrá emitir deuda pública para financiar todo tipo de gasto.","b) Podrá emitir deuda pública para financiar sus gastos en coordinación con el Estado.","c) Podrá emitir deuda pública para financiar gastos de inversión.","d) No podrá emitir deuda pública."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 45 EAPV: deuda pública para financiar gastos de inversión." },
  { n: 46, unidad: "organizacion-foral", pregunta: "Según lo establecido en el artículo 7 de la Ley 27/1983, de 25 de noviembre, de Relaciones entre las Instituciones Comunes de la Comunidad Autónoma y los Órganos Forales de sus Territorios Históricos, corresponde a los Territorios Históricos el desarrollo y ejecución de las normas emanadas de las instituciones comunes en la siguiente materia:", opciones: ["a) Operaciones de crédito y financieras en los términos que resultan del Título segundo de la presente ley.","b) Financiación de carreteras.","c) Planificación de carreteras.","d) Sanidad animal."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 7 LTH: sanidad animal es desarrollo y ejecución para los Territorios Históricos." },
  { n: 47, unidad: "concierto-economico", pregunta: "Según lo establecido en el artículo 22 de la Ley 27/1983, de 25 de noviembre, de Relaciones entre las Instituciones Comunes de la Comunidad Autónoma y los Órganos Forales de sus Territorios Históricos, el Consejo Vasco de Finanzas Públicas aprobará con carácter general la metodología de distribución de recursos y la determinación de las aportaciones de cada Territorio Histórico:", opciones: ["a) Siempre anualmente, salvo que concurran circunstancias excepcionales.","b) Para periodos mínimos de dos (2) ejercicios presupuestarios.","c) Para periodos mínimos de tres (3) ejercicios presupuestarios.","d) Para periodos mínimos de cuatro (4) ejercicios presupuestarios."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 22 LTH: periodos mínimos de 3 ejercicios presupuestarios." },
  { n: 48, unidad: "haciendas-locales", pregunta: "Según lo establecido en el artículo 18 de la Ley 27/1983, de 25 de noviembre, de Relaciones entre las Instituciones Comunes de la Comunidad Autónoma y los Órganos Forales de sus Territorios Históricos, las Haciendas Forales de los Territorios Históricos, para el adecuado ejercicio y financiación de todas las competencias que correspondan a sus órganos forales, dispondrán de las siguientes fuentes de recursos:", opciones: ["a) Ingresos por endeudamiento como ingresos ordinarios.","b) Rendimiento de los recargos y arbitrios como ingresos extraordinarios.","c) Variación de activos financieros como ingresos extraordinarios.","d) Los rendimientos procedentes de su patrimonio e ingresos de derecho privado como ingresos extraordinarios."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 18 LTH: variación de activos financieros es ingreso extraordinario. (a y b son ordinarios, d ordinario)." },
  { n: 49, unidad: "concierto-economico", pregunta: "Según el artículo 5 de la Ley 12/2002, de 23 de mayo, por la que se aprueba el Concierto Económico con la Comunidad Autónoma del País Vasco. Constituirán competencias exclusivas del Estado:", opciones: ["a) Los derechos a la importación en los Impuestos Especiales.","b) La baja inspección de la aplicación del concierto económico.","c) La regulación, gestión, inspección, revisión y recaudación de los derechos de exportación.","d) Los gravámenes a la importación en el Impuesto sobre el Valor Añadido."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 5 LCE: derechos de exportación son competencia exclusiva del Estado (no de importación)." },
  { n: 50, unidad: "concierto-economico", pregunta: "Según el artículo 48 de la Ley 12/2002, de 23 de mayo, por la que se aprueba el Concierto Económico con la Comunidad Autónoma del País Vasco, las relaciones financieras entre el Estado y el País Vasco se regirán por los principios siguientes:", opciones: ["a) Coordinación y colaboración con el Estado en materia de Deuda Pública.","b) Contribución del País Vasco a la solidaridad en los términos prevenidos en la Constitución y el Estatuto de Autonomía.","c) Coordinación y colaboración con el Estado para la suficiencia presupuestaria.","d) Coordinación y colaboración con el Estado en materia de estabilidad presupuestaria."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 48 LCE: estabilidad presupuestaria (también autonomía fiscal, solidaridad, coordinación con régimen tributario)." },
  { n: 51, unidad: "derecho-constitucional", pregunta: "Según el artículo 5 de la Ley 10/1982, de 24 de noviembre, básica de normalización del uso del Euskera:", opciones: ["a) Las lenguas propias del País Vasco son el euskera y el castellano.","b) Es un derecho lingüístico fundamental de los ciudadanos el derecho a expresarse en cualquier reunión en euskera.","c) Es un derecho lingüístico fundamental de los ciudadanos el derecho a recibir programas de televisión en ambas lenguas oficiales.","d) Es un derecho lingüístico fundamental de los ciudadanos el derecho desarrollar actividades políticas en ambas lenguas oficiales."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 5.2.d Ley 10/1982: derecho a recibir info en ambas lenguas a través de medios sociales (radio, prensa, TV)." },
  { n: 52, unidad: "organizacion-foral", pregunta: "Según el artículo 20, de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, la Diputación Foral podrá crear Comisiones Delegadas de carácter permanente o temporal en materias determinadas que afecten a más de un Departamento. En el Decreto de creación de las Comisiones no deberá figurar:", opciones: ["a) Los motivos de su creación.","b) El cargo de Secretario de la Comisión.","c) Los Departamentos Forales que se afecten a ella.","d) La duración."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 20 NF 3/1987: figuran motivos, departamentos y duración, no el cargo de Secretario." },
  { n: 53, unidad: "organizacion-foral", pregunta: "Según el artículo 17, de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, no corresponde a la Diputación Foral de Bizkaia:", opciones: ["a) Aprobar los proyectos de Norma Foral para su remisión a las Juntas Generales.","b) Fijar el Régimen General de Financiación de los Municipios del Territorio Histórico.","c) Aprobar los proyectos de Presupuestos del Territorio Histórico y sus Cuentas Generales y de Administración del Patrimonio y someterlos a la deliberación de las Juntas Generales para su aprobación definitiva.","d) Establecer las directrices de la acción de gobierno y ejercer la alta inspección de la Administración Foral y de las Entidades, Empresas y establecimientos de ella dependientes."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Fijar el régimen general de financiación municipal corresponde a las Juntas Generales, no a la Diputación Foral." },
  { n: 54, unidad: "organizacion-foral", pregunta: "Según lo dispuesto en el artículo 53 de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, los proyectos de Normas Forales presentados por la Diputación Foral a las Juntas Generales:", opciones: ["a) Irán acompañados de una exposición de motivos.","b) Indicarán pormenorizadamente, en la exposición, los motivos que hubieren dado origen a su elaboración y la finalidad perseguida.","c) Figurarán como anexos, en todo caso, la relación de disposiciones derogadas o modificadas.","d) Todas son correctas."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 53 NF 3/1987: las tres son requisitos." },
  { n: 55, unidad: "organizacion-foral", pregunta: "Según el artículo 63 de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, las disposiciones de carácter general se ajustarán al siguiente orden jerárquico normativo:", opciones: ["a) Normas Forales, emanadas de las Juntas Generales; Decretos Forales del Diputado General; Decretos Forales de la Diputación Foral; Ordenes Forales dictadas por los Diputados Forales de los Departamentos.","b) Normas Forales, emanadas de las Juntas Generales; Decretos Forales de la Diputación Foral; Decretos Forales del Diputado General; Ordenes Forales dictadas por los Diputados Forales de los Departamentos.","c) Normas Forales, emanadas de las Juntas Generales; Decretos Forales de la Diputación Foral; Ordenes Forales dictadas por los Diputados Forales de los Departamentos; Decretos Forales del Diputado General.","d) Normas Forales, emanadas de la Diputación Foral; Decretos Forales de la Diputación Foral; Ordenes Forales dictadas por los Diputados Forales de los Departamentos; Decretos Forales del Diputado General."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 63 NF 3/1987: NF JJGG > DF Diputación Foral > DF Diputado General > OF Diputados Forales." },
  { n: 56, unidad: "nfgt-tributos", pregunta: "Según la Norma Foral 2/2005, de 10 de marzo, General Tributaria del Territorio Histórico de Bizkaia, la obligación tributaria principal tiene por objeto:", opciones: ["a) El pago de la deuda tributaria.","b) El pago de la cuota tributaria.","c) El ingreso de la deuda tributaria.","d) El ingreso de la cuota tributaria."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 19 NFGT: obligación tributaria principal es el pago de la cuota tributaria." },
  { n: 57, unidad: "nfgt-principios", pregunta: "Según la Norma Foral 2/2005, de 10 de marzo, General Tributaria del Territorio Histórico de Bizkaia en relación con el ámbito temporal de las normas tributarias:", opciones: ["a) Las normas tributarias entrarán en vigor a los quince días de su completa publicación en el «Boletín Oficial de Bizkaia», si en ellas no se dispone otra cosa.","b) Las normas tributarias, salvo que se disponga lo contrario, no tendrán efecto retroactivo y se aplicarán a los tributos con periodo impositivo devengados a partir de su entrada en vigor y a los demás tributos cuyo período impositivo se inicie desde ese momento.","c) Las normas que regulen el régimen de infracciones y sanciones tributarias y el de los recargos tendrán efectos retroactivos respecto de los actos que sean firmes, cuando su aplicación resulte más favorable para el interesado.","d) Las normas que regulen el régimen de infracciones y sanciones tributarias y el de los recargos tendrán efectos retroactivos respecto de los actos que no sean firmes, cuando su aplicación resulte más favorable para el interesado."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 9 NFGT: retroactividad sólo para actos no firmes cuando sea más favorable." },
  { n: 58, unidad: "irpf", pregunta: "Según la Norma Foral 13/2013, de 5 de diciembre, del Impuesto sobre la Renta de las Personas Físicas, el importe de la indemnización exenta establecida para las indemnizaciones por despido no podrá superar la cantidad de:", opciones: ["a) Ciento cincuenta mil (150.000) euros.","b) Ciento setenta y cinco mil (175.000) euros.","c) Ciento ochenta mil (180.000) euros.","d) Doscientos mil (200.000) euros."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 9.5 NF IRPF Bizkaia: límite 180.000 euros." },
  { n: 59, unidad: "nfgt-tributos", pregunta: "De conformidad con la Norma Foral 4/1990, de 26 de junio, de Tasas, Precios Públicos y otros recursos tributarios de la Administración Foral de Bizkaia, las tasas:", opciones: ["a) Son tributos cuyo hecho imponible consiste en la utilización privativa o el aprovechamiento especial del dominio público, la prestación de servicios o la realización de actividades en régimen de Derecho público que se refieran, afecten o beneficien de modo particular al obligado tributario, cuando los servicios o actividades no sean de solicitud o recepción voluntaria para los obligados tributarios o no se presten o realicen por el sector privado.","b) Son tributos cuyo hecho imponible consiste en la utilización privativa o el aprovechamiento especial del dominio público, la prestación de servicios o la realización de actividades en régimen de Derecho público que se refieran, afecten o beneficien de modo particular al obligado tributario, cuando los servicios o actividades no sean de solicitud o recepción voluntaria para los obligados tributarios o no se presten o realicen por el sector público.","c) Son tributos cuyo hecho imponible lo constituye la obtención por el sujeto pasivo de un beneficio o de un aumento de valor de sus bienes como consecuencia de la realización de obras públicas o del establecimiento o ampliación de servicios públicos, por la Diputación Foral de Bizkaia.","d) Son tributos relativos a contraprestaciones pecuniarias que se satisfagan por la prestación de Servicios o realización de actividades administrativas de la competencia del Territorio Histórico de Bizkaia cuando los servicios o las actividades no sean de solicitud o recepción obligatoria por los administrados o que los servicios o actividades sean prestados o realizados por el sector privado."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Definición de tasas: servicios no voluntarios o no prestados por sector privado." },
  { n: 60, unidad: "isd", pregunta: "Según el Título II \"Hecho Imponible\" de la Norma Foral 4/2015, de 25 de marzo, del Impuesto sobre Sucesiones y Donaciones de Bizkaia, a efectos de este impuesto no serán títulos sucesorios:", opciones: ["a) La designación de sucesor en capitulaciones matrimoniales.","b) Los actos que resulten de la utilización del poder testatorio por el comisario, cualquiera que sea la forma que adopten.","c) Las adjudicaciones que, al disolverse la comunicación foral, se hagan a favor del cónyuge viudo o pareja de hecho, en pago de su mitad de los bienes comunicados.","d) El legado."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "NF ISD Bizkaia: las adjudicaciones por disolución de comunicación foral al cónyuge viudo NO son títulos sucesorios." },
  { n: 61, unidad: "is", pregunta: "De conformidad con el artículo 14 \"Concepto de sociedades patrimoniales\" de la Norma Foral 11/2013, de 5 de diciembre, del Impuesto sobre Sociedades, a los efectos de lo previsto en esta norma foral, tendrán la consideración de sociedades patrimoniales los contribuyentes en los que concurran, entre otras, que, al menos en noventa días del periodo impositivo, más de la mitad de su activo esté constituido por valores:", opciones: ["a) Que poseídos den cumplimiento a obligaciones legales y reglamentarias.","b) Que incorporen derechos de crédito nacidos de relaciones contractuales establecidas como consecuencia del desarrollo de actividades económicas.","c) O que más de la mitad de su activo no esté afecto a actividades económicas.","d) O que estén poseídos por sociedades de valores como consecuencia del ejercicio de la actividad constitutiva de su objeto."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 14 NF IS Bizkaia: más de la mitad del activo no afecto a actividades económicas (a, b, d son excepciones, no valores patrimoniales)." },
  { n: 62, unidad: "itp-ajd", pregunta: "En el Capítulo I \"Naturaleza y contenido\" del Título Preliminar de la Norma Foral 1/2011, de 24 de marzo, del Impuesto sobre Transmisiones Patrimoniales y Actos Jurídicos Documentados, se señala que:", opciones: ["a) El Impuesto sobre Transmisiones Patrimoniales y Actos Jurídicos Documentados es un tributo de naturaleza directa que, gravará las operaciones societarias.","b) El Impuesto sobre Transmisiones Patrimoniales y Actos Jurídicos Documentados es un tributo de naturaleza directa que, gravará las transmisiones patrimoniales onerosas.","c) Se considerarán bienes inmuebles las máquinas, instrumentos o utensilios destinados por el propietario de un inmueble a la industria o explotación que se realice en el mismo, aun cuando se les asigne valores distintos a los del inmueble.","d) No tendrán consideración de bienes inmuebles los buques destinados por su objeto y condiciones a permanecer en un punto fijo de un río, lago o costa."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "NF ITP-AJD Bizkaia: ITPAJD es indirecto (a, b incorrectas por 'directo'). Buques en punto fijo SÍ son inmuebles (d incorrecta)." },
  { n: 63, unidad: "haciendas-locales", pregunta: "De conformidad con el artículo 2, de la Norma Foral 4/2016, de 18 de mayo, del Impuesto sobre Bienes Inmuebles, constituye el hecho imponible del Impuesto sobre Bienes Inmuebles la titularidad del siguiente derecho sobre los bienes inmuebles rústicos, urbanos y de características especiales:", opciones: ["a) De un derecho real de hipoteca.","b) De un derecho real de servidumbre.","c) De un derecho real de usufructo.","d) De un derecho real de prenda."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 2 NF 4/2016 IBI: titularidad de usufructo (también concesión administrativa, superficie y propiedad)." },
  { n: 64, unidad: "procedimiento-administrativo", pregunta: "El artículo 4 de la Ley 39/2015, del Procedimiento Administrativo Común de las Administraciones Públicas, establece en relación a los interesados en el procedimiento administrativo:", opciones: ["a) Son aquellos cuyos intereses ilegítimos, individuales o colectivos puedan resultar afectados por la resolución y se personen en el procedimiento, cualquiera que sea el estado del procedimiento.","b) Son cuando la condición de interesado derivase de alguna relación jurídica transmisible, el derecho-habiente sucederá en tal condición cualquiera que sea el estado del procedimiento.","c) Son los que promuevan solo como titulares de derechos colectivos.","d) No se considera interesado a los que, sin haber iniciado el procedimiento, tengan derechos que puedan resultar afectados por la decisión que en el mismo se tome."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 4.2 Ley 39/2015: la b) es literal. La a) dice 'ilegítimos' (legítimos). La c) y d) restringen indebidamente." },
  { n: 65, unidad: "procedimiento-administrativo", pregunta: "Según lo establecido en la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, sobre el expediente administrativo es cierto que:", opciones: ["a) Cuando sea preciso remitir el expediente electrónico, se hará de acuerdo con lo previsto en el Esquema Nacional de Seguridad.","b) Formará parte del expediente administrativo los informes, solicitados antes de la resolución administrativa que no pongan fin al procedimiento.","c) El expediente se formará mediante la desagregación ordenada de documentos, pruebas, dictámenes, informes, acuerdos, notificaciones, y demás diligencias.","d) El expediente electrónico se enviará completo, y acompañado de un índice."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 70 Ley 39/2015: remisión según Esquema Nacional de Interoperabilidad. Pero el ENS también aplica; la c) dice 'desagregación' (es agregación) y la d) falta 'foliado, autentificado'." },
  { n: 66, unidad: "procedimiento-administrativo", pregunta: "De conformidad con el artículo 59 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas. Se entiende inicio del procedimiento por propia iniciativa:", opciones: ["a) La actuación derivada del conocimiento directo de las circunstancias, conductas o hechos objeto del procedimiento por el órgano que tiene atribuida la competencia de resolución.","b) La actuación derivada del conocimiento directo o indirecto de las circunstancias, conductas o hechos objeto del procedimiento por el órgano que tiene atribuida la competencia de resolución.","c) La actuación derivada del conocimiento directo o indirecto de las circunstancias, conductas o hechos objeto del procedimiento por el órgano que tiene atribuida la competencia de iniciación.","d) La actuación derivada del conocimiento directo de las circunstancias, conductas o hechos objeto del procedimiento por el órgano superior al que tiene atribuida la competencia de iniciación."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 59 Ley 39/2015: conocimiento directo o indirecto, órgano con competencia de iniciación." },
  { n: 67, unidad: "funcion-publica", pregunta: "De conformidad con lo establecido en la Ley 11/2022, de 1 de diciembre, de Empleo Público Vasco en relación con el devengo de las retribuciones:", opciones: ["a) Las retribuciones se devengarán y harán efectivas por mensualidades completas y vencidas y de acuerdo con la situación y derechos de la persona empleada referidos al primer día del mes a que correspondan, salvo en los casos señalados en esta ley, en que se liquidarán por días.","b) El importe de cada trienio comenzará a devengarse a partir del día primero del mes siguiente a su perfeccionamiento.","c) Las retribuciones del personal eventual se devengarán desde el día siguiente a su nombramiento hasta el día de su cese efectivo.","d) Ninguna de las opciones anteriores es exacta."], correcta: 0, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Ley 11/2022: la a) es la regla general literal." },
  { n: 68, unidad: "organizacion-foral", pregunta: "Según el artículo 27 de la Norma Foral 3/1987, de 13 de febrero, sobre elección, organización, régimen y funcionamiento de las Instituciones Forales del Territorio Histórico de Bizkaia, corresponde a la Diputada General en su calidad de Presidenta de la Diputación Foral:", opciones: ["a) Firmar en nombre de la Diputación los convenios o acuerdos de cooperación con los Municipios de Bizkaia y otras Administraciones.","b) Nombrar y separar a las Diputadas Forales y a los Diputados Forales.","c) Resolver los conflictos de atribuciones y competencia entre los distintos Departamentos de la Diputación Foral.","d) Suscribir a nombre de la Diputación Foral, escrituras, documentos o pólizas, dejando a salvo las atribuciones de los Diputados Forales para los contratos que según su cuantía les compete de acuerdo a la normativa foral reguladora."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 27 NF 3/1987: como Presidenta de la Diputación, resuelve conflictos entre Departamentos (b corresponde a la Diputada General como tal, a y d a Jefa de Administración)." },
  { n: 69, unidad: "itp-ajd", pregunta: "Según la Norma Foral 1/2011, de 24 de marzo, del Impuesto sobre Transmisiones Patrimoniales y Actos Jurídicos Documentados son transmisiones patrimoniales sujetas:", opciones: ["a) Todos los excesos de adjudicación declarados.","b) Las adjudicaciones en pago y para pago de deudas, así como las adjudicaciones presuntas en pago de asunción de deudas.","c) La constitución de derechos reales, préstamos, fianzas, arrendamientos, pensiones y concesiones administrativas, salvo cuando estas últimas no tengan por objeto la cesión del derecho a utilizar infraestructuras ferroviarias o inmuebles o instalaciones en puertos y aeropuertos.","d) Los contratos de aparcería y subarriendo."], correcta: 1, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "NF ITP-AJD: las adjudicaciones en pago y para pago de deudas son TPO. La a) sólo los excesos resultantes de operaciones; la c) la salvedad está al revés." },
  { n: 70, unidad: "iva", pregunta: "Según el artículo 6 \"Concepto de edificaciones\" de la Norma Foral 7/1994, de 9 de noviembre, del Impuesto sobre el Valor Añadido, no tendrán consideración de edificaciones:", opciones: ["a) Las plataformas para exploración y explotación de hidrocarburos.","b) Los puertos, aeropuertos y mercados.","c) Las minas, canteras o escoriales, pozos de petróleo o de gas u otros lugares de extracción de productos naturales.","d) Las instalaciones de recreo y deportivas que no sean accesorias de otras edificaciones."], correcta: 2, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "Art. 6 NF IVA Bizkaia: minas, canteras, pozos NO son edificaciones." },
  { n: 71, unidad: "haciendas-locales", pregunta: "Según la Norma Foral 7/1989, de 30 de junio, del Impuesto sobre Vehículos de Tracción Mecánica no están sujetos al impuesto:", opciones: ["a) Los vehículos aptos para circular por las vías públicas, cualesquiera que sean su clase y categoría, cuando el domicilio que conste en el permiso de circulación corresponda a un municipio del Territorio Histórico de Bizkaia.","b) Los vehículos que no habiendo sido dados de baja en los registros por antigüedad de su modelo, puedan ser autorizados para circular excepcionalmente con ocasión de exhibiciones, certámenes o carreras limitadas a los de esta naturaleza.","c) Los remolques y semirremolques arrastrados por vehículos de tracción mecánica cuya carga útil sea superior a 750 kilogramos.","d) Los remolques y semirremolques arrastrados por vehículos de tracción mecánica cuya carga útil sea inferior a 750 kilogramos."], correcta: 3, fuente: "DFB Administrativo Foral 2022 · teórico promoción interna", obsoleta: false, nota: "NF IVTM Bizkaia: remolques con carga útil inferior a 750 kg NO están sujetos." },
];
